function solve(nums) {
    const n = nums.length;

    // Step 1: Find the peak element index
    let peakIndex = 0;
    // The peak is the point where the array stops strictly increasing and starts strictly decreasing.
    // For a bitonic array, this is where nums[i] > nums[i+1] or it's the last element if it's purely increasing (though problem constraints imply a peak exists that transitions).
    // Since it is strictly increasing up to the peak, and strictly decreasing after, we look for the transition point.
    for (let i = 0; i < n - 1; i++) {
        if (nums[i] < nums[i + 1]) {
            peakIndex = i + 1;
        } else {
            // This is the first element that is not strictly greater than the previous one, 
            // meaning nums[i] >= nums[i+1]. Since it's bitonic, this is the start of the decreasing sequence.
            // If nums[i] > nums[i+1], nums[i] is the peak.
            // If nums[i] == nums[i+1], this violates the strictly increasing/decreasing property, but we assume valid input.
            // We found the peak index i.
            break;
        }
    }

    // Handle the case where the array is strictly increasing (e.g., [1, 2, 3]). 
    // In this case, the peak is the last element.
    if (peakIndex === n - 1 && n > 1 && nums[n-2] < nums[n-1]) {
        // This handles the case where the loop finished without breaking, meaning it was always increasing.
        // Since the problem implies a transition to decreasing, let's re-evaluate the peak finding for robustness.
        // The peak index is the largest index 'i' such that nums[i-1] < nums[i] (if i>0).

        peakIndex = 0;
        for (let i = 1; i < n; i++) {
            if (nums[i] > nums[i-1]) {
                peakIndex = i;
            } else {
                break;
            }
        }
    }


    // Step 2: Calculate the sum of the increasing part (0 to peakIndex)
    let sumIncreasing = 0;
    for (let i = 0; i <= peakIndex; i++) {
        sumIncreasing += nums[i];
    }

    // Step 3: Calculate the sum of the decreasing part (peakIndex to n-1)
    let sumDecreasing = 0;
    for (let i = peakIndex; i < n; i++) {
        sumDecreasing += nums[i];
    }

    // Step 4: Compare the sums and return the result
    if (sumIncreasing > sumDecreasing) {
        return 0;
    } else if (sumDecreasing > sumIncreasing) {
        return 1;
    } else {
        return -1;
    }
}

