    val n = nums.length

    // Step 1: Find the peak element index
    var peakIndex = 0
    // Find the largest index i such that nums[i] > nums[i-1].
    // Since the array is bitonic (strictly increasing then strictly decreasing),
    // the peak is the point where the increase stops.
    for (i <- 1 until n) {
      if (nums(i) > nums(i - 1)) {
        peakIndex = i
      } else {
        // The increase stopped at i-1, so the peak is i-1, but if nums[i] <= nums[i-1],
        // the previous element i-1 was the peak or we are already in the decreasing part.
        // Since we are looking for the *single* peak, the loop naturally finds the end of the increasing sequence.
        // If nums[i] <= nums[i-1], then i-1 is the peak index.
        if (nums(i) < nums(i - 1)) {
            // The peak must be i-1
